// Generated by OrchestKit Claude Plugin
// Created: 2026-07-20

/**
 * Analytics Writer Liveness Check — SessionStart Hook
 *
 * The local analytics pipeline fans out to several independent JSONL writers
 * under ~/.claude/analytics/ (skill-usage.jsonl, agent-usage.jsonl,
 * hook-timing.jsonl). Each writer can die silently — a dispatcher edit, a
 * matcher removal, or a refactor that drops one write path leaves the other
 * writers healthy, so nothing looks wrong until an audit reads the dead file
 * months later. Observed in the wild: skill-usage.jsonl recorded ONE entry
 * between 2026-03-07 and 2026-07-13 while agent-usage.jsonl logged hundreds
 * of events per day. Same failure class as the dead hook dispatch regression
 * (#959): registered-looking, silently dead.
 *
 * This hook closes the class with a peer comparison at SessionStart: if any
 * watched writer's file is stale (>= 48h since last write) while a sibling
 * writer is fresh (<= 24h), the pipeline is provably alive and that writer is
 * provably dead — emit one stderr banner naming the dead file(s) and ages.
 *
 * Deliberately silent when: the analytics dir is absent (fresh install /
 * consent off), fewer than two watched files exist (nothing to compare), or
 * ALL files are stale (machine was simply idle — not a writer failure).
 *
 * Opt-out: ORK_NO_ANALYTICS_LIVENESS_WARN=1.
 * Dir override (tests): ORK_ANALYTICS_DIR.
 *
 * Cost: one statSync per watched file (3), ~1ms. Async — non-blocking.
 *
 * Hook event: SessionStart
 */

import { statSync } from 'node:fs';
import { homedir } from 'node:os';
import { join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'lifecycle/analytics-liveness-check';
const OPT_OUT_ENV_VAR = 'ORK_NO_ANALYTICS_LIVENESS_WARN';
const DIR_ENV_VAR = 'ORK_ANALYTICS_DIR';

/** Writers that are expected to receive events whenever sessions run. */
const WATCHED_WRITERS = [
  'skill-usage.jsonl',
  'agent-usage.jsonl',
  'hook-timing.jsonl',
] as const;

/** A writer this old is considered dead — two full days without one event. */
const STALE_MS = 48 * 60 * 60 * 1000;
/** A sibling this recent proves the pipeline (and the machine) is active. */
const FRESH_MS = 24 * 60 * 60 * 1000;

interface WriterAge {
  /** Watched filename, e.g. "skill-usage.jsonl". */
  name: string;
  /** Milliseconds since last mtime. */
  ageMs: number;
}

/** Resolve the analytics dir: env override first, else ~/.claude/analytics. */
function resolveAnalyticsDir(): string {
  const override = process.env[DIR_ENV_VAR];
  if (override && override.trim().length > 0) return override;
  return join(homedir(), '.claude', 'analytics');
}

/** Stat each watched writer; missing files are skipped, not flagged. */
function measureWriterAges(dir: string, now: number): WriterAge[] {
  const ages: WriterAge[] = [];
  for (const name of WATCHED_WRITERS) {
    try {
      const st = statSync(join(dir, name));
      if (st.isFile()) ages.push({ name, ageMs: now - st.mtimeMs });
    } catch {
      // Missing writer file = never enabled here — not a liveness failure.
    }
  }
  return ages;
}

/**
 * Dead writers = stale files coexisting with at least one fresh sibling.
 * Returns [] when the comparison is impossible or the whole dir is idle.
 */
function findDeadWriters(ages: WriterAge[]): WriterAge[] {
  if (ages.length < 2) return [];
  const freshestAge = Math.min(...ages.map(a => a.ageMs));
  if (freshestAge > FRESH_MS) return []; // machine idle — every writer quiet
  return ages.filter(a => a.ageMs >= STALE_MS);
}

/** Compose the operator-facing warning with actionable scope. */
function formatWarning(dead: WriterAge[], dir: string): string {
  const days = (ms: number): string => (ms / 86_400_000).toFixed(1);
  const list = dead.map(w => `${w.name} (last write ${days(w.ageMs)}d ago)`).join(', ');
  return (
    `[orchestkit] WARN: analytics writer(s) look dead while siblings are active: ${list} ` +
    `in ${dir}. A dispatcher/matcher change likely dropped the write path ` +
    `(dead-writer class, see #959). Check the writer's hook registration in ` +
    `src/hooks/hooks.json + its entries map. Silence: ${OPT_OUT_ENV_VAR}=1.`
  );
}

export function analyticsLivenessCheck(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  if (process.env[OPT_OUT_ENV_VAR] === '1') return outputSilentSuccess();
  if (!input || typeof input !== 'object') return outputSilentSuccess();

  const dir = resolveAnalyticsDir();
  const ages = measureWriterAges(dir, Date.now());
  const dead = findDeadWriters(ages);
  if (dead.length === 0) return outputSilentSuccess();

  process.stderr.write(`${formatWarning(dead, dir)}\n`);
  ctx.log(
    HOOK_NAME,
    `Flagged dead analytics writer(s): ${dead.map(w => w.name).join(', ')}`,
  );

  return outputSilentSuccess();
}

// Export internals for unit testing only — not part of the public hook API.
export const _internals = {
  OPT_OUT_ENV_VAR,
  DIR_ENV_VAR,
  WATCHED_WRITERS,
  STALE_MS,
  FRESH_MS,
  resolveAnalyticsDir,
  measureWriterAges,
  findDeadWriters,
  formatWarning,
};
